import "./navbar.css";
import MenuVertical from './menuvertical/menu-vertical.js'

function Navbar() {

    return (

        <nav className="container-navbar">
            <ul className="nav-list">
                <a href="index.html"><img src="LOGO-B.png" alt='Logo' /></a>
                <li className="nav-item"><a href="index.html">INICIO</a></li>

                <li className="nav-item-menuv">
                    <a href="productos.html">PRODUCTOS</a>
                    <MenuVertical />
                </li>
                <li className="nav-item"><a href="contacto.html">CONTACTO</a></li>
            </ul>
        </nav>

    );
};

export default Navbar;
